public int[] fix45(int[] nums)
{
    int length = nums.length;
	int count = 0;
    for (int i = 0; i < length; i++){
		if (nums[i] == 4){
            count = count + 1;
        }
    }
    int[] replaceFives = new int[length]; //Make equal to count
    int j = 0;
    for (int i = 0; i < length; i++){
        if (nums[i] == 4){
            replaceFives[j] = nums[i + 1];
            j = j + 1;
        }
    }
    j = 0;
    for (int i = 0; i < count; i++){
    	if (nums[i] == 4){
            nums[i + 1] = 5;
        }
        else if (nums[i] == 5){
            nums[i] = replaceFives[j];
            j = j + 1;
        }
    }
    return replaceFives;
}

public boolean canBalance(int[] nums)
{
    int size = nums.length;
    int sum1 = 0;
    int sum2 = 0;
    int k = size - 1;
    int i = 0;
    int j = 0;
    int temp1 = 0;
    int temp2 = 0;
    while (j <  size)
    {
        if (k == i)
            return false;
    for (; k > i; k--)
    {	
        sum2 += nums[k];    
    }
    for (; i < k ; i++)
    {
            sum1 += nums[i];
    }
        if (sum1 == sum2)
		return true;
    i++;
    k--;
    sum1 = 0;
    sum2 = 0;
        if (j == 0)
        {
            temp1 = sum1;
            temp2 = sum2;
        }
        else if (sum1 < temp1 && sum2 > temp2)
            return false;
            else
            {
            	temp1 = sum1;
                temp2 = sum2;
            }

    }

    return false;


}

