        return true;
    }
    for (int i = 0; i < length - 1; i++)
    {
        if (nums[i] == val || nums[i + 1] == val)
        {
            counter = counter + 1;
        }
    }
    if (counter == length - 1)
    {
        return true;
    }
    else 
    {
		return false;
    }
}

public int centeredAverage(int[] nums)
{
    int max = nums[0];
    int min = nums[0];
    int sum = 0;

    for (int i = 0; i < nums.length; i++) {
        sum += nums[i];
        if (nums[i] > max) max = nums[i];
        if (nums[i] < min) min = nums[i];
    }
    return (sum - (max + min)) / (nums.length - 2);
}

