public int loneSum(int a, int b, int c)
{
    if (a == b) {
        int loneSum = a + c;
    }
    else if (a == c) {
        int loneSum = a + b;
    }
    else if (b == c) {
        int loneSum = a + b;
    }
    else {
        int loneSum = a + b + c;
    }
    return loneSum;
}

